object PushTokenStore {
    private const val PREFS = "push_token_store"
    private const val KEY_TOKEN = "token"

    fun get(context: Context): String? {
        return context.getSharedPreferences(PREFS, Context.MODE_PRIVATE)
            .getString(KEY_TOKEN, null)
    }

    fun set(context: Context, token: String) {
        context.getSharedPreferences(PREFS, Context.MODE_PRIVATE)
            .edit()
            .putString(KEY_TOKEN, token)
            .apply()
    }

    fun subscribe(context: Context, topic: String) {
        context.getSharedPreferences(PREFS, Context.MODE_PRIVATE)
            .edit()
            .putString("topic_$topic", "subscribed")
            .apply()
    }

    fun unsubscribe(context: Context, topic: String) {
        context.getSharedPreferences(PREFS, Context.MODE_PRIVATE)
            .edit()
            .remove("topic_$topic")
            .apply()
    }
}

class HybridWebActivity : AppCompatActivity() {

    private lateinit var webView: HybridWebView
    private lateinit var cameraPermissionLauncher: ActivityResultLauncher<String>
    private var pendingPermissionCallback: ((Boolean) -> Unit)? = null

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)

        webView = HybridWebView(this).apply {
            onPermissionRequest = { resources, callback ->
                if (resources.contains(PermissionRequest.RESOURCE_VIDEO_CAPTURE)) {
                    if (ContextCompat.checkSelfPermission(
                            this@HybridWebActivity,
                            Manifest.permission.CAMERA
                        ) == PackageManager.PERMISSION_GRANTED
                    ) {
                        callback(true)
                    } else {
                        pendingPermissionCallback = callback
                        cameraPermissionLauncher.launch(Manifest.permission.CAMERA)
                    }
                } else {
                    callback(false)
                }
            }
        }

        cameraPermissionLauncher = registerForActivityResult(
            ActivityResultContracts.RequestPermission()
        ) { granted ->
            pendingPermissionCallback?.invoke(granted)
            pendingPermissionCallback = null
        }

        val container = FrameLayout(this)
        container.addView(
            webView,
            FrameLayout.LayoutParams(
                FrameLayout.LayoutParams.MATCH_PARENT,
                FrameLayout.LayoutParams.MATCH_PARENT
            )
        )
        setContentView(container)

        webView.loadMobileApp("https://your-mobile-web-app.example.com")
    }

    override fun onResume() {
        super.onResume()
        webView.onResume()
    }

    override fun onPause() {
        webView.onPause()
        super.onPause()
    }

    override fun onDestroy() {
        webView.destroySafely()
        super.onDestroy()
    }
}

object HybridJsApi {
